import{_ as e,o as l,c as a,a2 as o}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"景岳全书","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/04-明清/01-景岳全书（张介宾）.md","filePath":"tcm-data/04-明清/01-景岳全书（张介宾）.md","lastUpdated":1781084559000}'),r={name:"tcm-data/04-明清/01-景岳全书（张介宾）.md"};function n(s,t,d,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="景岳全书" tabindex="-1">景岳全书 <a class="header-anchor" href="#景岳全书" aria-label="Permalink to &quot;景岳全书&quot;">​</a></h1><blockquote><p>张介宾（1563-1640年），浙江绍兴人 明代温补学派集大成者 代表作：《景岳全书》《类经》《类经图翼》</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>字号</strong>：字会卿，号景岳</li><li><strong>生平</strong>：早年从军，后弃戎从医，钻研《内经》30年</li><li><strong>著作</strong>：《景岳全书》64卷，《类经》32卷（对《内经》的重大学术整理）</li><li><strong>学术地位</strong>：<strong>温补学派</strong>的代表人物，主张&quot;阳非有余，阴亦不足&quot;</li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-阳非有余——与朱震亨的对话" tabindex="-1">1. 阳非有余——与朱震亨的对话 <a class="header-anchor" href="#_1-阳非有余——与朱震亨的对话" aria-label="Permalink to &quot;1. 阳非有余——与朱震亨的对话&quot;">​</a></h3><p>张介宾针对朱震亨&quot;阳常有余，阴常不足&quot;提出：</p><blockquote><p><strong>「阳非有余，阴亦不足。阳惟畏其衰，阴惟畏其盛。」</strong></p></blockquote><p>他认为：</p><ul><li>人体的阳气并非&quot;有余&quot;，而是<strong>容易衰败</strong></li><li>阴精也不是&quot;常不足&quot;，而是<strong>太过则会生寒湿</strong></li><li>治疗上应当<strong>温养阳气为主</strong></li></ul><p>这和黄元御&quot;病于阳虚者，尽人皆是&quot;的立场一致。</p><h3 id="_2-命门学说" tabindex="-1">2. 命门学说 <a class="header-anchor" href="#_2-命门学说" aria-label="Permalink to &quot;2. 命门学说&quot;">​</a></h3><blockquote><p><strong>「命门为水火之府，阴阳之宅，精气之海，死生之窦。」</strong></p></blockquote><p>张介宾将命门视为人体的根本，提出：</p><ul><li><strong>命门之火</strong> = 生命的原动力</li><li><strong>命门之水</strong> = 生命的物质基础</li></ul><h3 id="_3-八阵分类法" tabindex="-1">3. 八阵分类法 <a class="header-anchor" href="#_3-八阵分类法" aria-label="Permalink to &quot;3. 八阵分类法&quot;">​</a></h3><p>张介宾将方剂按&quot;<strong>八阵</strong>&quot;分类（仿兵法）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">八阵</th><th style="text-align:left;">对应治则</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>补阵</strong></td><td style="text-align:left;">补虚</td></tr><tr><td style="text-align:left;"><strong>和阵</strong></td><td style="text-align:left;">和解</td></tr><tr><td style="text-align:left;"><strong>攻阵</strong></td><td style="text-align:left;">攻实</td></tr><tr><td style="text-align:left;"><strong>散阵</strong></td><td style="text-align:left;">发散</td></tr><tr><td style="text-align:left;"><strong>寒阵</strong></td><td style="text-align:left;">清热</td></tr><tr><td style="text-align:left;"><strong>热阵</strong></td><td style="text-align:left;">温里</td></tr><tr><td style="text-align:left;"><strong>固阵</strong></td><td style="text-align:left;">收敛固涩</td></tr><tr><td style="text-align:left;"><strong>因阵</strong></td><td style="text-align:left;">随证治之</td></tr></tbody></table><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>左归丸</strong></td><td style="text-align:left;">熟地、山药、枸杞、山萸、菟丝子、鹿角胶、龟板胶、牛膝</td><td style="text-align:left;">真阴不足</td></tr><tr><td style="text-align:left;"><strong>右归丸</strong></td><td style="text-align:left;">熟地、山药、山萸、枸杞、鹿角胶、菟丝子、杜仲、当归、肉桂、附子</td><td style="text-align:left;">命门火衰</td></tr><tr><td style="text-align:left;"><strong>镇阴煎</strong></td><td style="text-align:left;">熟地、牛膝、泽泻、桂心、炙甘草、附子</td><td style="text-align:left;">阴虚于下，火浮于上</td></tr><tr><td style="text-align:left;"><strong>保阴煎</strong></td><td style="text-align:left;">生地、熟地、芍药、山药、续断、黄芩、黄柏、甘草</td><td style="text-align:left;">阴虚内热</td></tr></tbody></table><hr><h2 id="四、经典名言" tabindex="-1">四、经典名言 <a class="header-anchor" href="#四、经典名言" aria-label="Permalink to &quot;四、经典名言&quot;">​</a></h2><blockquote><p><strong>「阳非有余，阴亦不足。」</strong></p></blockquote><blockquote><p><strong>「命门为水火之府，阴阳之宅，精气之海，死生之窦。」</strong></p></blockquote><blockquote><p><strong>「善补阳者，必于阴中求阳，则阳得阴助而生化无穷；善补阴者，必于阳中求阴，则阴得阳升而泉源不竭。」</strong></p></blockquote><blockquote><p><strong>「医者，理也。不明理，不可以为医。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><ul><li><strong>&quot;阴中求阳，阳中求阴&quot;</strong> 成为中医配伍的经典原则</li><li>右归丸、左归丸是温补肾阳和滋补肾阴的代表方</li><li>命门学说对黄元御有深远影响</li></ul><hr><p><em>本条目为精简框架版。可与黄元御的命门学说对比分析。</em></p>',34)])])}const c=e(r,[["render",n]]);export{f as __pageData,c as default};
